import React, { useEffect, useState, useCallback } from 'react';
import { api } from '../utils/api';

const styles = {
  container: {
    backgroundColor: '#0B0F14',
    color: '#E5E7DB',
    fontFamily: "'Plus Jakarta Sans', sans-serif",
    minHeight: '100vh',
    padding: 20,
    boxSizing: 'border-box',
  },
  header: {
    marginBottom: 20,
  },
  tabs: {
    display: 'flex',
    marginBottom: 12,
    gap: 12,
  },
  tabButton: (active) => ({
    backgroundColor: active ? '#1F2A37' : 'transparent',
    border: `1px solid #1F2A37`,
    borderRadius: 6,
    padding: '6px 14px',
    cursor: 'pointer',
    color: '#E5E7DB',
    fontWeight: active ? '600' : '400',
    userSelect: 'none',
    transition: 'background-color 0.25s',
  }),
  searchInput: {
    width: '100%',
    maxWidth: 400,
    padding: '8px 12px',
    borderRadius: 6,
    border: '1px solid #1F2A37',
    backgroundColor: '#0F1620',
    color: '#E5E7DB',
    fontSize: 16,
    marginBottom: 20,
    outline: 'none',
  },
  articlesGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill,minmax(320px,1fr))',
    gap: 20,
  },
  card: {
    backgroundColor: '#0F1620',
    border: '1px solid #1F2A37',
    borderRadius: 14,
    overflow: 'hidden',
    cursor: 'pointer',
    display: 'flex',
    flexDirection: 'column',
    height: '100%',
    transition: 'box-shadow 0.25s',
  },
  cardHover: {
    boxShadow: '0 0 10px #22C55E',
  },
  thumbnail: {
    width: '100%',
    height: 160,
    objectFit: 'cover',
    backgroundColor: '#1F2A37',
  },
  cardContent: {
    padding: 16,
    flexGrow: 1,
    display: 'flex',
    flexDirection: 'column',
  },
  headline: {
    fontFamily: "'Plus Jakarta Sans', sans-serif",
    fontWeight: 700,
    fontSize: 18,
    marginBottom: 8,
    lineHeight: 1.3,
    flexGrow: 1,
  },
  metaRow: {
    display: 'flex',
    justifyContent: 'space-between',
    fontSize: 13,
    color: '#9CA3AF',
    marginBottom: 12,
  },
  sentimentBadge: (sentiment) => {
    let bgColor = '#6B7280'; // Neutral gray
    if (sentiment === 'Bullish') bgColor = '#22C55E';
    else if (sentiment === 'Bearish') bgColor = '#EF4444';
    return {
      backgroundColor: bgColor,
      color: '#0B0F14',
      borderRadius: 14,
      padding: '2px 10px',
      fontWeight: 600,
      fontSize: 13,
      userSelect: 'none',
      whiteSpace: 'nowrap',
    };
  },
  tagsContainer: {
    marginTop: 'auto',
    display: 'flex',
    flexWrap: 'wrap',
    gap: 8,
  },
  tag: {
    fontFamily: "'JetBrains Mono', monospace",
    backgroundColor: '#1F2A37',
    borderRadius: 6,
    padding: '4px 8px',
    fontSize: 13,
    userSelect: 'none',
  },
  noArticles: {
    textAlign: 'center',
    marginTop: 40,
    fontSize: 16,
    color: '#9CA3AF',
  },
};

function formatTimestamp(timestamp) {
  const date = new Date(timestamp);
  if (isNaN(date)) return '';
  const now = new Date();
  const diff = (now - date) / 1000;
  if (diff < 60) return 'Just now';
  if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
  return date.toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
}

export default function PortfolioNewsFeed() {
  const [articles, setArticles] = useState([]);
  const [filter, setFilter] = useState('All'); // All, Bullish, Bearish
  const [search, setSearch] = useState('');
  const [hoveredId, setHoveredId] = useState(null);

  const fetchArticles = useCallback(async () => {
    try {
      const data = await api('/news/portfolio');
      if (Array.isArray(data)) setArticles(data);
      else setArticles([]);
    } catch {
      setArticles([]);
    }
  }, []);

  useEffect(() => {
    fetchArticles();
    const interval = setInterval(fetchArticles, 60000);
    return () => clearInterval(interval);
  }, [fetchArticles]);

  const filteredArticles = articles.filter((article) => {
    if (filter !== 'All' && article.sentiment !== filter) return false;
    if (search.trim() === '') return true;
    const keyword = search.trim().toLowerCase();
    return (
      article.headline.toLowerCase().includes(keyword) ||
      article.source.toLowerCase().includes(keyword) ||
      (article.relatedSymbols &&
        article.relatedSymbols.some((sym) => sym.toLowerCase().includes(keyword)))
    );
  });

  return (
    <div style={styles.container} aria-label="Portfolio News Feed">
      <header style={styles.header}>
        <div style={styles.tabs} role="tablist" aria-label="Filter news by sentiment">
          {['All', 'Bullish', 'Bearish'].map((tab) => (
            <button
              key={tab}
              type="button"
              role="tab"
              aria-selected={filter === tab}
              onClick={() => setFilter(tab)}
              style={styles.tabButton(filter === tab)}
              tabIndex={filter === tab ? 0 : -1}
            >
              {tab}
            </button>
          ))}
        </div>
        <input
          type="search"
          aria-label="Search news articles"
          placeholder="Search articles..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={styles.searchInput}
        />
      </header>
      {filteredArticles.length === 0 ? (
        <div style={styles.noArticles} role="alert" aria-live="polite">
          No articles found.
        </div>
      ) : (
        <section style={styles.articlesGrid}>
          {filteredArticles.map((article) => (
            <article
              key={article.id || article.headline}
              style={{
                ...styles.card,
                ...(hoveredId === article.id ? styles.cardHover : {}),
              }}
              onClick={() => {
                if (article.url) window.open(article.url, '_blank', 'noopener,noreferrer');
              }}
              onKeyDown={(e) => {
                if (e.key === 'Enter' || e.key === ' ') {
                  e.preventDefault();
                  if (article.url) window.open(article.url, '_blank', 'noopener,noreferrer');
                }
              }}
              tabIndex={0}
              role="link"
              aria-label={`Open article: ${article.headline}`}
              onMouseEnter={() => setHoveredId(article.id)}
              onMouseLeave={() => setHoveredId(null)}
            >
              {article.thumbnail ? (
                <img
                  src={article.thumbnail}
                  alt=""
                  aria-hidden="true"
                  style={styles.thumbnail}
                  loading="lazy"
                />
              ) : null}
              <div style={styles.cardContent}>
                <h3 style={styles.headline}>{article.headline}</h3>
                <div style={styles.metaRow}>
                  <span>{article.source}</span>
                  <time dateTime={article.timestamp}>{formatTimestamp(article.timestamp)}</time>
                </div>
                <div style={styles.sentimentBadge(article.sentiment)}>{article.sentiment}</div>
                {article.relatedSymbols && article.relatedSymbols.length > 0 && (
                  <div style={styles.tagsContainer} aria-label="Related symbols">
                    {article.relatedSymbols.map((sym) => (
                      <span key={sym} style={styles.tag}>
                        {sym}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            </article>
          ))}
        </section>
      )}
    </div>
  );
}
